// Parser la réponse du Chef Agent
// Claude retourne des tool_use blocks qu'on extrait
const response = $input.first().json;
const content = response.content || [];

const toolCalls = content
  .filter(block => block.type === 'tool_use')
  .map(block => ({
    agent: block.name,
    action: block.input?.action,
    data: block.input || {},
    tool_use_id: block.id
  }));

const textBlock = content.find(b => b.type === 'text');
const reasoning = textBlock?.text || '';

// Log du raisonnement du chef agent
console.log('[Chef Agent] Raisonnement:', reasoning);
console.log('[Chef Agent] Agents activés:', toolCalls.map(t => t.agent).join(', '));

return toolCalls.map(call => ({ json: { ...call, reasoning, timestamp: new Date().toISOString() } }));

// Agréger les résultats de tous les sous-agents
const results = $input.all().map(item => item.json);
const agents_activated = [...new Set(results.map(r => r.agent).filter(Boolean))];
return [{
  json: {
    status: 'completed',
    agents_activated,
    results,
    timestamp: new Date().toISOString()
  }
}];
